mapper.select:
SELECT ROLE.CO_ID, ROLE.ROLE_ID, ROLE.ROLE_CD, ROLE.ROLE_NM, ROLE.ROLE_DESC, ROLE.USE_FLG, ROLE.CRE_DT, ROLE.CRE_USR_ID, ROLE.UPD_DT, ROLE.UPD_USR_ID FROM ADM_ROLE ROLE WHERE 1=1 AND ROLE.CO_ID = #{coId}
AND ROLE.ROLE_ID = #{roleId}
AND ROLE.ROLE_CD = #{roleCd}
AND ROLE.ROLE_NM ILIKE '%' || #{roleNm} || '%'
AND ROLE.USE_FLG = #{useFlg}
ORDER BY ${sort.sortField} ${sort.sortType}, UPD_DT DESC
ORDER BY UPD_DT DESC
LIMIT #{pagination.pageSize} OFFSET (#{pagination.current} - 1) * #{pagination.pageSize}

SELECT COUNT(*)
	FROM ADM_ROLE ROLE
	WHERE 1=1 
		AND ROLE.CO_ID = #{coId} 

		AND ROLE.ROLE_ID = #{roleId}


		AND ROLE.ROLE_CD = #{roleCd}


		AND ROLE.ROLE_NM ILIKE '%' || #{roleNm} || '%'


		AND ROLE.USE_FLG = #{useFlg}

SELECT ROLE.CO_ID, ROLE.ROLE_ID, ROLE.ROLE_CD, ROLE.ROLE_NM, ROLE.ROLE_DESC, ROLE.USE_FLG, ROLE.CRE_DT, ROLE.CRE_USR_ID, ROLE.UPD_DT, ROLE.UPD_USR_ID FROM ADM_ROLE ROLE WHERE 1=1 AND ROLE.CO_ID = #{coId}
AND ROLE.ROLE_ID = #{roleId}
AND ROLE.ROLE_CD = #{roleCd}
AND ROLE.ROLE_NM ILIKE '%' || #{roleNm} || '%'
AND ROLE.USE_FLG = #{useFlg}
LIMIT 1

SELECT AUTH.CO_ID, AUTH.ROLE_ID, ROLE.ROLE_CD, PERM.PERM_ID, PERM.PERM_CD, PGM.PGM_ID, PGM.PGM_CD, PGM.PGM_TP_CD, AUTH.USE_FLG AS ACTIVE_YN FROM ADM_ROLE_AUTH AUTH LEFT JOIN ADM_ROLE ROLE ON (AUTH.CO_ID = ROLE.CO_ID AND AUTH.ROLE_ID = ROLE.ROLE_ID) LEFT JOIN COM_PGM PGM ON (AUTH.CO_ID = PGM.CO_ID AND AUTH.PGM_ID = PGM.PGM_ID) LEFT JOIN COM_PERM PERM ON (AUTH.CO_ID = PERM.CO_ID AND AUTH.PERM_ID = PERM.PERM_ID) WHERE 1=1 AND AUTH.CO_ID = #{coId}
AND AUTH.ROLE_ID = #{roleId}
AND ROLE.ROLE_CD = #{roleCd}
AND AUTH.PGM_ID = #{pgmId}
AND ROLE.USE_FLG = #{useFlg}

mapper.delete:
DELETE FROM ADM_ROLE_AUTH
	WHERE CO_ID = #{coId}
	AND ROLE_ID = #{roleId}

DELETE FROM ADM_ROLE_AUTH AUTH
	WHERE AUTH.CO_ID = #{coId}

		AND AUTH.ROLE_ID = #{roleId}


		AND AUTH.PGM_ID = #{pgmId}


		AND AUTH.PERM_ID = #{permId}
